const KEY = 'meal-in-flight-draft';
const TTL_MS = 30 * 60 * 1000;

export interface StoredDraftIngredient {
    food_item_id: string;
    amount: number;
}

export interface StoredMealDraft {
    id?: string;
    name: string;
    notes: string;
    default_scale: number;
    image_path?: string;
    ingredients: StoredDraftIngredient[];
}

interface StoredEnvelope {
    savedAt: number;
    draft: StoredMealDraft;
}

export function saveDraft(draft: StoredMealDraft): void {
    const envelope: StoredEnvelope = { savedAt: Date.now(), draft };
    sessionStorage.setItem(KEY, JSON.stringify(envelope));
}

export function readDraft(): StoredMealDraft | null {
    const raw = sessionStorage.getItem(KEY);
    if (!raw) return null;
    const envelope = JSON.parse(raw) as StoredEnvelope;
    if (Date.now() - envelope.savedAt > TTL_MS) {
        sessionStorage.removeItem(KEY);
        return null;
    }
    return envelope.draft;
}

export function clearDraft(): void {
    sessionStorage.removeItem(KEY);
}
